const autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);

// POST /billing/preview-upgrade
router.post('/preview-upgrade', async (req, res) => {
  const { customerId, targetPlanId } = req.body;

  if (!customerId || !targetPlanId) {
    return res.status(400).json({ error: 'customerId and targetPlanId are required' });
  }

