const router = express.Router();
const autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);

// POST /billing/preview-upgrade
router.post('/preview-upgrade', async (req, res) => {
  const { customerId, targetPlanId } = req.body;

  if (!customerId || !targetPlanId) {
    return res.status(400).json({ error: 'customerId and targetPlanId are required' });
  }

  try {
    const preview = await autumn.billing.previewAttach({
      customerId,
      productId: targetPlanId,
    });
    return res.status(200).json(preview);
  } catch (err) {
    return res.status(502).json({
      error: 'Billing service unavailable',
      details: err.message,
    });
  }
});

// POST /billing/confirm-upgrade
router.post('/confirm-upgrade', async (req, res) => {
  const { customerId, targetPlanId, confirmed } = req.body;

  if (customerId === undefined || targetPlanId === undefined || confirmed === undefined) {
    return res.status(400).json({ error: 'customerId, targetPlanId, and confirmed are required' });
  }

  if (confirmed === false) {
    return res.status(200).json({ status: 'cancelled' });
  }

  try {
    await autumn.attach({ customerId, productId: targetPlanId });
    return res.status(200).json({
      status: 'upgraded',
